parameters.jsCode:
// Input is your 2‑item array
const items = $input.all();

// Extract the two objects
const msg = items[0].json;      // { userId, message }
const data = items[1].json;     // big health object

// Build a single combined object
const combined = {
  ...data,
  // keep existing user_id, also add plain userId if you want
  userId: msg.userId,
  message: msg.message,
};

// Return as array of items for n8n
return [
  {
    json: combined,
  },
];

/**
 * Advanced Health Analytics Node
 * Logic: Overall Risk, Clinical Flagging, & Biological Age
 */

for (const item of $input.all()) {
    const d = item.json;

    // --- 1. CORE DOMAIN CALCULATIONS (Previously Defined) ---
    const hWeights = { intercept: -5.5, age: 0.02, sex: 0.8, cp: 0.75, trestbps: 0.015, chol: 0.005, fbs: 0.2, restecg: 0.3, thalach: -0.02, exang: 0.9, oldpeak: 0.5, slope: 0.4, ca: 1.1, thal: 0.8, bmi: 0.1 };
    let hZ = hWeights.intercept + (d.age * hWeights.age) + (d.sex * hWeights.sex) + (d.cp * hWeights.cp) + (d.trestbps * hWeights.trestbps) + (d.chol * hWeights.chol) + (d.fbs * hWeights.fbs) + (d.restecg * hWeights.restecg) + (d.thalach * hWeights.thalach) + (d.exang * hWeights.exang) + (d.oldpeak * hWeights.oldpeak) + (d.slope * hWeights.slope) + (d.ca * hWeights.ca) + (d.thal * hWeights.thal) + (d.bmi * hWeights.bmi);
    const heartP = 1 / (1 + Math.exp(-hZ));

    const lWeights = { intercept: -4.536, age: 0.077, bmi: -0.025, copd: 0.36, fam: 0.58, smoke: 0.26, dur: 0.032, quit: -0.031 };
    let lZ = lWeights.intercept + (d.age * lWeights.age) + (d.bmi * lWeights.bmi) + (d.copd * lWeights.copd) + (d.family_hx * lWeights.fam) + (d.is_smoker * lWeights.smoke) + (d.duration * lWeights.dur) + (d.years_quit * lWeights.quit);
    const lungP = 1 / (1 + Math.exp(-lZ));

    const fib4 = (d.age * d.ast) / (d.platelets * Math.sqrt(d.alt));
    const mets_ir = (Math.log((2 * d.glucose) + d.triglycerides) * d.bmi) / Math.log(d.hdl);

    // --- 2. CALCULATE OVERALL HEALTH RISK (Weighted Ensemble) ---
    // We weigh Heart and Metabolism higher as they are systemic drivers.
    const overallRisk = (heartP * 0.35) + (lungP * 0.20) + (Math.min(fib4 / 4, 1) * 0.15) + (Math.min(mets_ir / 50, 1) * 0.30);

    // --- 3. CALCULATE BIOLOGICAL AGE (KDM-Lite) ---
    // Every high-risk marker adds "years" to your birth age.
    let bioAgeDelta = 0;
    if (heartP > 0.5) bioAgeDelta += 5;
    if (mets_ir > 31.8) bioAgeDelta += 4;
    if (fib4 > 1.45) bioAgeDelta += 2;
    if (d.bmi > 30) bioAgeDelta += 3;
    const biologicalAge = d.age + bioAgeDelta;

    // --- 4. FLAG HEALTH RISKS (Clinical Alerts) ---
    let flags = [];
    if (heartP > 0.7) flags.push("CRITICAL_HEART_RISK");
    if (fib4 > 3.25) flags.push("ADVANCED_LIVER_FIBROSIS_INDICATED");
    if (mets_ir > 45) flags.push("SEVERE_INSULIN_RESISTANCE");
    if (lungP > 0.05) flags.push("HIGH_LUNG_SCREENING_PRIORITY");

    // --- OUTPUT ASSIGNMENT ---
    item.json.analytics = {
        overall_health_risk: (overallRisk * 100).toFixed(2) + "%",
        biological_age: biologicalAge.toFixed(1),
        age_differential: (biologicalAge - d.age).toFixed(1) + " years",
        clinical_flags: flags.length > 0 ? flags : ["NO_URGENT_FLAGS"],
        risk_profile: overallRisk > 0.6 ? "HIGH" : (overallRisk > 0.3 ? "MODERATE" : "LOW")
    };
}

return $input.all();

parameters.functionCode:
const input = $json.body;

// BMI
const height_m = input.height / 100;
const bmi = input.weight / (height_m * height_m);

// SIGNALS
let signals = [];

if (input.sleep < 6) signals.push("poor_sleep");
else if (input.sleep < 7) signals.push("moderate_sleep");
else signals.push("good_sleep");

if (input.steps < 4000) signals.push("sedentary");
else if (input.steps < 8000) signals.push("low_activity");
else signals.push("active");

if (bmi > 25) signals.push("overweight");
if (input.waist > 90) signals.push("high_waist_risk");

if (input.diet_quality === "unhealthy") signals.push("unhealthy_diet");
if (input.diet_pattern === "processed") signals.push("processed_food");

if (input.smoking_type === "smoker") signals.push("smoking_risk");
if (input.smoking_type === "ex_smoker") signals.push("past_smoking_risk");

if (input.alcohol === "heavy") signals.push("high_alcohol");
if (input.alcohol === "moderate") signals.push("moderate_alcohol");

if (input.job === "desk_job") signals.push("sedentary_job");
if (input.job === "construction") signals.push("lung_exposure");

if (input.stress === "high") signals.push("chronic_stress");
if (input.screen_time > 6) signals.push("high_screen_time");

if (input.family_history.includes("diabetes")) signals.push("genetic_risk_diabetes");
if (input.family_history.includes("heart_disease")) signals.push("genetic_risk_heart");

if (input.medical_history.length > 0) signals.push("existing_condition");

// RISKS
let heartRisk = 0, metabolicRisk = 0, lungRisk = 0, mentalRisk = 0, liverRisk = 0, sleepRisk = 0;

if (signals.includes("sedentary")) heartRisk += 12;
if (signals.includes("overweight")) heartRisk += 12;
if (signals.includes("smoking_risk")) heartRisk += 25;
if (signals.includes("chronic_stress")) heartRisk += 10;

if (signals.includes("high_waist_risk")) metabolicRisk += 25;
if (signals.includes("unhealthy_diet")) metabolicRisk += 20;

if (signals.includes("smoking_risk")) lungRisk += 35;

if (signals.includes("poor_sleep")) mentalRisk += 25;
if (signals.includes("chronic_stress")) mentalRisk += 30;

if (signals.includes("high_alcohol")) liverRisk += 35;

if (signals.includes("poor_sleep")) sleepRisk += 40;

const normalize = x => Math.min(x, 100);

heartRisk = normalize(heartRisk);
metabolicRisk = normalize(metabolicRisk);
lungRisk = normalize(lungRisk);
mentalRisk = normalize(mentalRisk);
liverRisk = normalize(liverRisk);
sleepRisk = normalize(sleepRisk);

const overallRisk =
  heartRisk * 0.2 +
  metabolicRisk * 0.2 +
  mentalRisk * 0.15 +
  lungRisk * 0.15 +
  liverRisk * 0.1 +
  sleepRisk * 0.1;

// BIO AGE
const healthIndex = overallRisk;
const ageShift = (healthIndex - 30) / 10;

let bioAge = input.age + ageShift;

if (input.waist > 90) bioAge += 2;
if (signals.includes("active")) bioAge -= 1;

bioAge = Math.max(input.age - 5, bioAge);
bioAge = Math.min(input.age + 15, bioAge);
bioAge = Math.round(bioAge);

return [{
  json: {
    input,
    signals,
    risks: {
      heart: heartRisk,
      metabolic: metabolicRisk,
      lung: lungRisk,
      mental: mentalRisk,
      liver: liverRisk,
      sleep: sleepRisk,
      overall: Math.round(overallRisk)
    },
    biologicalAge: {
      realAge: input.age,
      biologicalAge: bioAge,
      ageDifference: bioAge - input.age
    }
  }
}];

const risks = $json.risks;

const topRisks = Object.entries(risks)
  .filter(([key]) => key !== 'overall')
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3);

return [{
  json: {
    ...$json,
    topRisks
  }
}];

