const core = items[0].json;
const ai = items[1].json;

return [{
  input: core.input,
  signals: core.signals,
  risks: core.risks,
  biologicalAge: core.biologicalAge,
  topRisks: core.topRisks,

  summary: ai.summary,
  future_risk: ai.future_risk,
  actions: ai.actions,
  keyvalues: ai.keyvalues
}];

let content = $input.first().json.message.content;

// Iteratively parse escaped JSON string until it's an object
while (typeof content === 'string') {
  content = JSON.parse(content);
}

const extractedJson = content;

// Return in n8n format
return [{ json: extractedJson }];
